#include <iostream>
int main() {
    for (int i{0}; i < 5; ++i) {
        if (i == 3) break;
        std::cout << i << " ";
    }
}

#include <iostream>
int main() {
    for (int i{0}; i < 5; ++i) {
        if (i % 2 == 0) continue;
        std::cout << i << " ";
    }
}

#include <iostream>
int main() {
    int i{0};
    while (i < 5) {
        if (i == 2) { ++i; continue; }
        std::cout << i << " ";
        ++i;
    }
}
